//! Layer-by-layer reference tests.
//!
//! Compares whisper.cpp output against Python OpenAI whisper reference fixtures.
//! Reference data is generated by `scripts/generate_test_fixtures.py`.
//!
//! Test coverage:
//! - Model architecture parameters (n_vocab, n_layers, n_heads, etc.)
//! - Full transcription text (segment-level)
//! - Segment timestamps
//! - Language detection
//! - Token-level output
//!
//! Requires:
//! - Model: third-party/whisper.cpp/models/ggml-tiny.en.bin
//! - Fixture: tests/fixtures/reference_tiny_en_jfk.json

use std::ffi::{CStr, CString};
use std::path::{Path, PathBuf};

use any_stt::config::Backend;
use any_stt::SttEngine;
use whisper_backend::ffi::*;
use whisper_backend::WhisperEngine;

// ---- Helpers ----

fn repo_root() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("../..")
        .canonicalize()
        .unwrap()
}

fn model_path() -> PathBuf {
    repo_root().join("third-party/whisper.cpp/models/ggml-tiny.en.bin")
}

fn jfk_wav_path() -> PathBuf {
    repo_root().join("third-party/whisper.cpp/samples/jfk.wav")
}

fn fixture_path() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("tests/fixtures/reference_tiny_en_jfk.json")
}

fn read_wav(path: &Path) -> Vec<f32> {
    let reader = hound::WavReader::open(path).expect("failed to open WAV");
    let spec = reader.spec();
    assert_eq!(spec.channels, 1);
    assert_eq!(spec.sample_rate, 16000);
    let max_val = (1 << (spec.bits_per_sample - 1)) as f32;
    reader
        .into_samples::<i32>()
        .map(|s| s.unwrap() as f32 / max_val)
        .collect()
}

#[derive(serde::Deserialize)]
struct Fixture {
    model: String,
    mel_spectrogram: MelData,
    encoder: EncoderData,
    decoder: DecoderData,
    transcription: TranscriptionData,
}

#[derive(serde::Deserialize)]
struct MelData {
    audio_samples: usize,
    audio_duration_s: f64,
    mel_padded: TensorStats,
}

#[derive(serde::Deserialize)]
struct TensorStats {
    shape: Vec<usize>,
    min: f64,
    max: f64,
    mean: f64,
    std: f64,
    head: Vec<f64>,
}

#[derive(serde::Deserialize)]
struct EncoderData {
    final_output: TensorStats,
    blocks: std::collections::HashMap<String, serde_json::Value>,
}

#[derive(serde::Deserialize)]
struct DecoderData {
    logits: TensorStats,
    blocks: std::collections::HashMap<String, serde_json::Value>,
}

#[derive(serde::Deserialize)]
struct TranscriptionData {
    text: String,
    language: String,
    segments: Vec<SegmentData>,
}

#[derive(serde::Deserialize)]
struct SegmentData {
    id: usize,
    start: f64,
    end: f64,
    text: String,
    tokens: Vec<i64>,
}

fn load_fixture() -> Fixture {
    let path = fixture_path();
    if !path.exists() {
        panic!(
            "Fixture not found: {}. Run: python scripts/generate_test_fixtures.py",
            path.display()
        );
    }
    let data = std::fs::read_to_string(&path).unwrap();
    serde_json::from_str(&data).unwrap()
}

fn skip_if_no_model() -> bool {
    let p = model_path();
    if !p.exists() {
        eprintln!("SKIPPED: model not found at {}", p.display());
        return true;
    }
    false
}

/// Create a raw whisper context for low-level FFI tests.
unsafe fn create_ctx() -> *mut WhisperContext {
    let path = CString::new(model_path().to_str().unwrap()).unwrap();
    let mut cparams = whisper_context_default_params();
    cparams.use_gpu = false;
    whisper_init_from_file_with_params(path.as_ptr(), cparams)
}

// ======================================================================
// Model architecture tests
// ======================================================================

#[test]
fn model_architecture_matches_tiny_en() {
    if skip_if_no_model() {
        return;
    }
    let ctx = unsafe { create_ctx() };
    assert!(!ctx.is_null());

    unsafe {
        // tiny.en: 4 encoder layers, 4 decoder layers, 6 heads, 384 state
        assert_eq!(whisper_model_n_vocab(ctx), 51864);
        assert_eq!(whisper_model_n_audio_ctx(ctx), 1500);
        assert_eq!(whisper_model_n_audio_state(ctx), 384);
        assert_eq!(whisper_model_n_audio_head(ctx), 6);
        assert_eq!(whisper_model_n_audio_layer(ctx), 4);
        assert_eq!(whisper_model_n_text_ctx(ctx), 448);
        assert_eq!(whisper_model_n_text_state(ctx), 384);
        assert_eq!(whisper_model_n_text_head(ctx), 6);
        assert_eq!(whisper_model_n_text_layer(ctx), 4);
        assert_eq!(whisper_model_n_mels(ctx), 80);

        whisper_free(ctx);
    }
}

