#[test]
fn encoder_output_shape_matches_reference() {
    let fixture = load_fixture();

    // Encoder output: [1, 1500, 384] for tiny.en
    assert_eq!(fixture.encoder.final_output.shape, vec![1, 1500, 384]);
}

#[test]
fn encoder_has_4_blocks() {
    let fixture = load_fixture();
    assert_eq!(fixture.encoder.blocks.len(), 4);
    assert!(fixture.encoder.blocks.contains_key("block_0"));
    assert!(fixture.encoder.blocks.contains_key("block_3"));
}

#[test]
fn encoder_block_outputs_are_finite() {
    let fixture = load_fixture();

    for (name, block) in &fixture.encoder.blocks {
        let block: std::collections::HashMap<String, TensorStats> =
            serde_json::from_value(block.clone()).unwrap();

        for (layer_name, stats) in &block {
            assert!(
                stats.mean.is_finite(),
                "encoder {name}/{layer_name}: mean is not finite"
            );
            assert!(
                stats.std.is_finite(),
                "encoder {name}/{layer_name}: std is not finite"
            );
            assert!(
                stats.min <= stats.max,
                "encoder {name}/{layer_name}: min > max"
            );
        }
    }
}

