// ======================================================================
// Full transcription comparison (whisper.cpp vs Python reference)
// ======================================================================

#[test]
fn transcription_text_matches_reference() {
    if skip_if_no_model() {
        return;
    }
    let fixture = load_fixture();
    let hw = any_stt::detect_hardware();
    let engine = WhisperEngine::new(&model_path(), "en", Backend::Cpu, hw).unwrap();
    let audio = read_wav(&jfk_wav_path());

    let result = engine.transcribe(&audio).unwrap();
    let cpp_text = result.text.trim().to_lowercase();
    let py_text = fixture.transcription.text.trim().to_lowercase();

    eprintln!("whisper.cpp: {cpp_text:?}");
    eprintln!("Python ref:  {py_text:?}");

    // Core content must match. Allow minor punctuation/whitespace differences.
    assert!(
        cpp_text.contains("ask not what your country can do for you"),
        "missing core phrase 1 in whisper.cpp output: {cpp_text:?}"
    );
    assert!(
        cpp_text.contains("ask what you can do for your country"),
        "missing core phrase 2 in whisper.cpp output: {cpp_text:?}"
    );

    // Words should largely overlap
    let py_words: Vec<&str> = py_text.split_whitespace().collect();
    let cpp_words: Vec<&str> = cpp_text.split_whitespace().collect();
    let matching = py_words
        .iter()
        .filter(|w| cpp_words.contains(w))
        .count();
    let overlap = matching as f64 / py_words.len() as f64;
    assert!(
        overlap >= 0.85,
        "word overlap too low: {overlap:.2} ({matching}/{}) — cpp={cpp_text:?} py={py_text:?}",
        py_words.len()
    );
}

