#[test]
fn segment_count_matches_reference() {
    if skip_if_no_model() {
        return;
    }
    let fixture = load_fixture();

    let ctx = unsafe { create_ctx() };
    assert!(!ctx.is_null());

    let audio = read_wav(&jfk_wav_path());
    let params = unsafe { shim_default_params(WhisperSamplingStrategy::Greedy) };
    let lang = CString::new("en").unwrap();
    unsafe {
        shim_params_set_language(params, lang.as_ptr());
        shim_params_set_print_progress(params, false);
        shim_params_set_print_realtime(params, false);
        shim_params_set_print_timestamps(params, false);
    }

    let ret = unsafe { shim_whisper_full(ctx, params, audio.as_ptr(), audio.len() as i32) };
    unsafe { shim_free_params(params) };
    assert_eq!(ret, 0);

    let n_segments = unsafe { whisper_full_n_segments(ctx) } as usize;
    eprintln!("whisper.cpp segments: {n_segments}");
    eprintln!("Python ref segments:  {}", fixture.transcription.segments.len());

    // Segment count may differ slightly between implementations.
    // Allow a tolerance of ±1.
    let diff = (n_segments as i64 - fixture.transcription.segments.len() as i64).unsigned_abs();
    assert!(
        diff <= 1,
        "segment count differs by {diff}: cpp={n_segments}, py={}",
        fixture.transcription.segments.len()
    );

    unsafe { whisper_free(ctx) };
}

#[test]
fn segment_timestamps_are_reasonable() {
    if skip_if_no_model() {
        return;
    }
    let fixture = load_fixture();

    let ctx = unsafe { create_ctx() };
    let audio = read_wav(&jfk_wav_path());
    let params = unsafe { shim_default_params(WhisperSamplingStrategy::Greedy) };
    let lang = CString::new("en").unwrap();
    unsafe {
        shim_params_set_language(params, lang.as_ptr());
        shim_params_set_print_progress(params, false);
        shim_params_set_print_realtime(params, false);
        shim_params_set_print_timestamps(params, false);
    }
    let ret = unsafe { shim_whisper_full(ctx, params, audio.as_ptr(), audio.len() as i32) };
    unsafe { shim_free_params(params) };
    assert_eq!(ret, 0);

    let n_segments = unsafe { whisper_full_n_segments(ctx) };

    for i in 0..n_segments {
        // whisper.cpp timestamps are in centiseconds (10ms units)
        let t0 = unsafe { whisper_full_get_segment_t0(ctx, i) };
        let t1 = unsafe { whisper_full_get_segment_t1(ctx, i) };
        let t0_s = t0 as f64 / 100.0;
        let t1_s = t1 as f64 / 100.0;

        eprintln!("Segment {i}: {t0_s:.2}s - {t1_s:.2}s");

        // Basic sanity: t0 < t1, both non-negative, within audio duration
        assert!(t0 >= 0, "segment {i}: t0 is negative");
        assert!(t1 > t0, "segment {i}: t1 <= t0");
        assert!(
            t1_s <= fixture.mel_spectrogram.audio_duration_s + 1.0,
            "segment {i}: t1 ({t1_s}s) exceeds audio duration ({}s)",
            fixture.mel_spectrogram.audio_duration_s
        );
    }

    // First segment should start near 0
    if n_segments > 0 {
        let first_t0 = unsafe { whisper_full_get_segment_t0(ctx, 0) } as f64 / 100.0;
        assert!(first_t0 < 2.0, "first segment starts too late: {first_t0}s");
    }

    unsafe { whisper_free(ctx) };
}

#[test]
fn per_segment_text_matches_reference() {
    if skip_if_no_model() {
        return;
    }
    let fixture = load_fixture();

    let ctx = unsafe { create_ctx() };
    let audio = read_wav(&jfk_wav_path());
    let params = unsafe { shim_default_params(WhisperSamplingStrategy::Greedy) };
    let lang = CString::new("en").unwrap();
    unsafe {
        shim_params_set_language(params, lang.as_ptr());
        shim_params_set_print_progress(params, false);
        shim_params_set_print_realtime(params, false);
        shim_params_set_print_timestamps(params, false);
    }
    let ret = unsafe { shim_whisper_full(ctx, params, audio.as_ptr(), audio.len() as i32) };
    unsafe { shim_free_params(params) };
    assert_eq!(ret, 0);

    let n_segments = unsafe { whisper_full_n_segments(ctx) } as usize;

    // Collect all text from whisper.cpp
    let mut cpp_texts = Vec::new();
    for i in 0..n_segments {
        let text_ptr = unsafe { whisper_full_get_segment_text(ctx, i as i32) };
        if !text_ptr.is_null() {
            let text = unsafe { CStr::from_ptr(text_ptr) }
                .to_string_lossy()
                .to_string();
            eprintln!("cpp segment {i}: {text:?}");
            cpp_texts.push(text);
        }
    }

    // Compare individual segments against reference
    let min_segments = n_segments.min(fixture.transcription.segments.len());
    for i in 0..min_segments {
        let cpp = cpp_texts[i].trim().to_lowercase();
        let py = fixture.transcription.segments[i].text.trim().to_lowercase();

        eprintln!("Segment {i} cpp: {cpp:?}");
        eprintln!("Segment {i}  py: {py:?}");

        // Each segment's core words should overlap significantly
        let py_words: Vec<&str> = py.split_whitespace().collect();
        let cpp_words: Vec<&str> = cpp.split_whitespace().collect();
        if py_words.is_empty() {
            continue;
        }
        let matching = py_words.iter().filter(|w| cpp_words.contains(w)).count();
        let overlap = matching as f64 / py_words.len() as f64;
        assert!(
            overlap >= 0.70,
            "segment {i}: word overlap too low: {overlap:.2} — cpp={cpp:?} py={py:?}"
        );
    }

    unsafe { whisper_free(ctx) };
}

#[test]
fn token_probabilities_are_valid() {
    if skip_if_no_model() {
        return;
    }

    let ctx = unsafe { create_ctx() };
    let audio = read_wav(&jfk_wav_path());
    let params = unsafe { shim_default_params(WhisperSamplingStrategy::Greedy) };
    let lang = CString::new("en").unwrap();
    unsafe {
        shim_params_set_language(params, lang.as_ptr());
        shim_params_set_print_progress(params, false);
        shim_params_set_print_realtime(params, false);
        shim_params_set_print_timestamps(params, false);
    }
    let ret = unsafe { shim_whisper_full(ctx, params, audio.as_ptr(), audio.len() as i32) };
    unsafe { shim_free_params(params) };
    assert_eq!(ret, 0);

    let n_segments = unsafe { whisper_full_n_segments(ctx) };

    for i in 0..n_segments {
        let n_tokens = unsafe { whisper_full_n_tokens(ctx, i) };
        assert!(n_tokens > 0, "segment {i}: no tokens");

        for j in 0..n_tokens {
            let token_id = unsafe { whisper_full_get_token_id(ctx, i, j) };
            let token_p = unsafe { whisper_full_get_token_p(ctx, i, j) };

            // Token ID should be within vocab range
            assert!(
                token_id >= 0 && token_id < 51864,
                "segment {i} token {j}: id {token_id} out of range"
            );

            // Probability should be in [0, 1]
            assert!(
                token_p >= 0.0 && token_p <= 1.0,
                "segment {i} token {j}: probability {token_p} out of range"
            );
        }
    }

    unsafe { whisper_free(ctx) };
}

// ======================================================================
// Reference value range validation
// ======================================================================

#[test]
fn encoder_layer_value_ranges_are_reasonable() {
    let fixture = load_fixture();

    // Encoder final output stats from Python
    let enc = &fixture.encoder.final_output;
    assert!(enc.min > -20.0, "encoder output min too low: {}", enc.min);
    assert!(enc.max < 20.0, "encoder output max too high: {}", enc.max);
    assert!(
        enc.mean.abs() < 1.0,
        "encoder output mean too far from 0: {}",
        enc.mean
    );
    assert!(
        enc.std > 0.1 && enc.std < 5.0,
        "encoder output std out of range: {}",
        enc.std
    );
}

#[test]
fn decoder_logits_value_ranges_are_reasonable() {
    let fixture = load_fixture();

    let logits = &fixture.decoder.logits;
    assert!(
        logits.min > -50.0,
        "decoder logits min too low: {}",
        logits.min
    );
    assert!(
        logits.max < 50.0,
        "decoder logits max too high: {}",
        logits.max
    );
}

#[test]
fn encoder_layer_stats_monotonic_check() {
    let fixture = load_fixture();

    // Check that encoder blocks produce progressively transformed representations
    // (std should generally change across layers as features are refined)
    let mut stds = Vec::new();
    for i in 0..4 {
        let block: std::collections::HashMap<String, TensorStats> = serde_json::from_value(
            fixture.encoder.blocks[&format!("block_{i}")].clone(),
        )
        .unwrap();
        stds.push(block["block_output"].std);
    }

    eprintln!("Encoder block output stds: {stds:?}");

    // All stds should be positive and finite
    for (i, s) in stds.iter().enumerate() {
        assert!(s.is_finite() && *s > 0.0, "block {i}: std is {s}");
    }
}

#[test]
fn decoder_cross_attention_activates() {
    let fixture = load_fixture();

    // Cross-attention output should have non-trivial activation
    // (proves encoder output is being used by decoder)
    for i in 0..4 {
        let block: std::collections::HashMap<String, TensorStats> = serde_json::from_value(
            fixture.decoder.blocks[&format!("block_{i}")].clone(),
        )
        .unwrap();

        let cross_attn = &block["cross_attn_output"];
        assert!(
            cross_attn.std > 0.01,
            "decoder block {i}: cross_attn std too low ({}), attention may not be activating",
            cross_attn.std
        );
    }
}
